import urllib.request, struct, math, time
GPU="http://127.0.0.1:8093/hidden-embed"; CPU="http://172.22.160.1:8090/hidden-embed"
def post(url,toks):
    body=struct.pack("<%dI"%len(toks),*toks)
    req=urllib.request.Request(url,data=body,headers={"Content-Type":"application/octet-stream"})
    t=time.time(); d=urllib.request.urlopen(req,timeout=120).read(); dt=time.time()-t
    v=list(struct.unpack("<%df"%(len(d)//4),d)); return v,dt
toks=[785,4124,16599,35835,916,279,15678,5562,13]
# warm
post(GPU,toks); 
gv,gt=post(GPU,toks); cv,ct=post(CPU,toks)
gmag=math.sqrt(sum(x*x for x in gv)); cmag=math.sqrt(sum(x*x for x in cv))
print("GPU latency=%.3fs  CPU latency=%.3fs  speedup=%.1fx"%(gt,ct,ct/gt))
print("GPU L2norm=%.3f  CPU L2norm=%.3f (both non-unit => raw anisotropic, not normalized)"%(gmag,cmag))
print("first5 GPU:",[round(x,4) for x in gv[:5]])
print("first5 CPU:",[round(x,4) for x in cv[:5]])
